/**
 * @param {number[]} nums
 * @param {number[][]} queries
 * @return {number[]}
 */
function solve(nums, queries) {
    const N = nums.length;
    const results = [];

    for (const query of queries) {
        const [l, r, k] = query;

        // 1. Identify all positive even numbers present in nums[l..r]
        const removedEvenNumbers = new Set();
        for (let i = l; i <= r; i++) {
            const num = nums[i];
            if (num % 2 === 0 && num > 0) {
                removedEvenNumbers.add(num);
            }
        }

        // 2. Determine the count of removed even numbers
        const removedCount = removedEvenNumbers.size;

        // 3. Find the k-th smallest remaining positive even number.
        // The sequence of all positive even numbers is: 2, 4, 6, 8, 10, 12, ...
        // The n-th positive even number is 2*n.

        // If no numbers were removed, the k-th remaining even number is the k-th even number, which is 2*k.
        // If 'removedCount' numbers were removed, this means we are looking for an even number
        // whose rank in the full sequence (1st, 2nd, 3rd, ...) is such that after removing 'removedCount' elements, 
        // it becomes the k-th remaining element.

        // Let X be the target even number we are looking for, so X = 2 * R, where R is its rank in the full sequence.
        // The number of removed even numbers less than or equal to X must be <= removedCount.

        // A simpler approach:
        // The k-th remaining number corresponds to the (k + number_of_removed_smaller_or_equal_to_it)-th number in the original sequence.

        // Since we are looking for the k-th smallest *remaining* number, and all removed numbers are positive even,
        // the target number, let's call it T, must be an even number.

        // In the infinite sequence 2, 4, 6, ..., the k-th remaining number T has a rank R in the full sequence such that:
        // R - (Number of removed evens <= T) = k
        // R = k + (Number of removed evens <= T)

        // We are looking for the smallest even number T such that:
        // (Number of removed evens <= T) + k is the rank of T in the full sequence.

        // Let's use binary search on the answer T (which must be an even number).
        // The search space for T is [2, 2 * (k + removedCount + small_buffer)].

        // Since k <= 10^9 and removedCount <= N (10^5), the max rank R is around 10^9.
        // Max T is around 2 * (10^9 + 10^5) ~ 2 * 10^9.

        let low = 1; // Represents the rank R (since 2*1 is the first even number)
        // A safe upper bound for R: k + N. Since k <= 10^9 and N <= 10^5.
        let high = k + N + 1; 
        let ans_rank = -1;

        while (low <= high) {
            const mid_rank = Math.floor((low + high) / 2);
            const T = 2 * mid_rank;

            // Count how many removed even numbers are less than or equal to T
            let countRemovedLeqT = 0;
            for (const removedNum of removedEvenNumbers) {
                if (removedNum <= T) {
                    countRemovedLeqT++;
                }
            }

            // The rank of T in the remaining sequence is:
            // R_remaining = R_original - (Count of removed <= T)
            const remaining_rank = mid_rank - countRemovedLeqT;

            if (remaining_rank >= k) {
                // T might be the answer, or we can find a smaller one that still satisfies remaining_rank >= k
                // We want the smallest T such that remaining_rank >= k.
                ans_rank = mid_rank;
                high = mid_rank - 1;
            } else {
                // T is too small, remaining_rank < k. We need a larger T.
                low = mid_rank + 1;
            }
        }

        if (ans_rank !== -1) {
            results.push(2 * ans_rank);
        } else {
            // This should theoretically not happen given the problem constraints (k <= 10^9) 
            // and the search space upper bound, as there is always a large enough even number.
            // However, if k is extremely large and the search space was insufficient, this would be a fallback.
            // For robustness, if k is very large, the required answer is just 2*k if no evens were removed.
            // Since the BS should cover it, we assume the BS found the answer.
        }
    }

    return results;
}

