import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        List<Long> results = new ArrayList<>();
        int N = nums.length;

        for (long[] query : queries) {
            int l = (int) query[0];
            int r = (int) query[1];
            long k = query[2];

            // 1. Identify all positive even numbers present in nums[l..r]
            Set<Long> removedEvenNumbers = new HashSet<>();
            for (int i = l; i <= r; i++) {
                long num = nums[i];
                if (num % 2 == 0 && num > 0) {
                    removedEvenNumbers.add(num);
                }
            }

            // 2. Binary search on the rank R of the target even number T = 2*R in the full sequence (2, 4, 6, ...)
            // We are looking for the smallest rank R such that:
            // R - (Count of removed evens <= 2*R) >= k

            // Lower bound for rank R: k (if no evens were removed)
            long lowRank = 1;
            // Upper bound for rank R: k + |removedEvenNumbers| + 1.
            // Since k <= 10^9 and |removedEvenNumbers| <= 10^5, k + N + 1 is a safe upper bound.
            long highRank = k + N + 2; 
            long ansRank = -1;

            while (lowRank <= highRank) {
                long midRank = lowRank + (highRank - lowRank) / 2;
                long T = 2 * midRank;

                // Count how many removed even numbers are less than or equal to T
                int countRemovedLeqT = 0;
                for (long removedNum : removedEvenNumbers) {
                    if (removedNum <= T) {
                        countRemovedLeqT++;
                    }
                }

                // The rank of T in the remaining sequence is:
                // R_remaining = R_original - (Count of removed <= T)
                long remainingRank = midRank - countRemovedLeqT;

                if (remainingRank >= k) {
                    // T (or a smaller one) could be the answer. Try to find a smaller rank.
                    ansRank = midRank;
                    highRank = midRank - 1;
                } else {
                    // T is too small, remainingRank < k. Need a larger rank.
                    lowRank = midRank + 1;
                }
            }

            if (ansRank != -1) {
                results.add(2 * ansRank);
            } else {
                // Should not happen based on constraints, but as a safeguard, 
                // if k is so large that even with all possible removals, we don't reach k, 
                // the constraints suggest we should always find an answer within the calculated highRank.
            }
        }

        long[] finalResult = new long[results.size()];
        for (int i = 0; i < results.size(); i++) {
            finalResult[i] = results.get(i);
        }
        return finalResult;
    }
}
